function normalizeUrl(value: string): string | undefined {
  try {
    const parsed = new URL(value.trim());
    parsed.protocol = parsed.protocol.toLowerCase();
    parsed.hostname = parsed.hostname.toLowerCase();
    parsed.hash = "";
    return parsed.href;
  } catch {
    return undefined;
  }
}

