app.put("/bookmarks/:id", (req, res) => {
  const userId = requireUserId(req);
  const id = Number(req.params.id);
  const existing = Number.isInteger(id) ? getBookmark(id, userId) : undefined;

  if (!existing) {
    if (Number.isInteger(id) && hasSharedBookmarkAccess(id, userId)) {
      return res.status(403).json({ error: "shared bookmarks are read-only" });
    }

    return res.status(404).json({ error: "bookmark not found" });
  }

  const { url, title, description, folder_id, tag_ids, version } = req.body as {
    url?: unknown;
    title?: unknown;
    description?: unknown;
    folder_id?: unknown;
    tag_ids?: unknown;
    version?: unknown;
  };

  const expectedVersion = parseRequiredVersion(version);
  if (expectedVersion === undefined) {
    return res.status(400).json({ error: "version must be a positive integer" });
  }

  if (expectedVersion !== existing.version) {
    return res.status(409).json({ current: getBookmarkWithTags(id, userId) });
  }

  if (url !== undefined && !isNonEmptyString(url)) {
    return res.status(400).json({ error: "url must be a non-empty string" });
  }

  if (typeof url === "string" && !isValidUrl(url)) {
    return res.status(400).json({ error: "url must be a valid URL" });
  }

  if (title !== undefined && !isNonEmptyString(title)) {
    return res.status(400).json({ error: "title must be a non-empty string" });
  }

  const parsedFolderId = parseFolderId(folder_id);
  if (folder_id !== undefined && parsedFolderId === undefined) {
    return res.status(400).json({ error: "folder_id must be an existing folder id or null" });
  }

  if (typeof parsedFolderId === "number" && !folderExists(parsedFolderId, userId)) {
    if (hasSharedFolderAccess(parsedFolderId, userId)) {
      return res.status(403).json({ error: "shared folders are read-only" });
    }

    return res.status(400).json({ error: "folder_id does not reference an existing folder" });
  }

  const parsedTagIds = parseTagIds(tag_ids);
  if (parsedTagIds === undefined || !tagIdsBelongToUser(parsedTagIds, userId)) {
    return res.status(400).json({ error: "tag_ids must reference existing tags for the current user" });
  }

  const nextUrl = typeof url === "string" ? url.trim() : existing.url;
  const nextTitle = typeof title === "string" ? title.trim() : existing.title;
  const nextDescription =
    description === undefined
      ? existing.description
      : typeof description === "string" && description.length > 0
        ? description
        : null;
  const nextFolderId = folder_id === undefined ? existing.folder_id : parsedFolderId;
  const updatedAt = new Date().toISOString();

  const updateBookmark = db.transaction((): boolean => {
    const result = db.prepare(
      `
        UPDATE bookmarks
        SET url = ?, title = ?, description = ?, folder_id = ?, version = version + 1, updated_at = ?
        WHERE id = ? AND user_id = ? AND version = ?
      `,
    ).run(nextUrl, nextTitle, nextDescription, nextFolderId, updatedAt, id, userId, expectedVersion);

    if (result.changes === 0) {
      return false;
    }

    if (tag_ids !== undefined) {
      replaceBookmarkTags(id, parsedTagIds);
    }

    return true;
  });

  if (!updateBookmark()) {
    return res.status(409).json({ current: getBookmarkWithTags(id, userId) });
  }

  return res.status(200).json(getBookmarkWithTags(id, userId));
});

