app.delete("/tags/:id", (req, res) => {
  const userId = requireUserId(req);
  const id = Number(req.params.id);
  const existing = Number.isInteger(id) ? getTag(id, userId) : undefined;

  if (!existing) {
    return res.status(404).json({ error: "tag not found" });
  }

  db.prepare("DELETE FROM tags WHERE id = ? AND user_id = ?").run(id, userId);
  return res.status(204).send();
});

app.post("/folders", (req, res) => {
  const userId = requireUserId(req);
  const { name } = req.body as { name?: unknown };

  if (!isNonEmptyString(name)) {
    return res.status(400).json({ error: "name must be a non-empty string" });
  }

  const now = new Date().toISOString();
  const result = db
    .prepare(
      `
        INSERT INTO folders (user_id, name, created_at, updated_at)
        VALUES (?, ?, ?, ?)
      `,
    )
    .run(userId, name.trim(), now, now);

  return res.status(201).json(getFolder(Number(result.lastInsertRowid), userId));
});

app.get("/folders", (req, res) => {
  const userId = requireUserId(req);
  const folders = db
    .prepare("SELECT id, user_id, name, created_at, updated_at FROM folders WHERE user_id = ? ORDER BY id ASC")
    .all(userId) as Folder[];

  return res.status(200).json(folders);
});

app.get("/shared/folders", (req, res) => {
  const userId = requireUserId(req);
  const folders = db
    .prepare(
      `
        SELECT
          folders.id,
          folders.user_id,
          folders.name,
          folders.created_at,
          folders.updated_at,
          folder_shares.created_at AS shared_at,
          users.id AS owner_id,
          users.email AS owner_email,
          users.created_at AS owner_created_at
        FROM folder_shares
        INNER JOIN folders ON folders.id = folder_shares.folder_id
        INNER JOIN users ON users.id = folder_shares.owner_user_id
        WHERE folder_shares.shared_with_user_id = ?
        ORDER BY folder_shares.created_at ASC, folders.id ASC
      `,
    )
    .all(userId) as Array<
    Folder & {
      shared_at: string;
      owner_id: number;
      owner_email: string;
      owner_created_at: string;
    }
  >;

  const response: SharedFolder[] = folders.map((folder) => ({
    id: folder.id,
    user_id: folder.user_id,
    name: folder.name,
    created_at: folder.created_at,
    updated_at: folder.updated_at,
    shared_at: folder.shared_at,
    owner: {
      id: folder.owner_id,
      email: folder.owner_email,
      created_at: folder.owner_created_at,
    },
  }));

  return res.status(200).json(response);
});

app.post("/folders/:id/share", (req, res) => {
  const userId = requireUserId(req);
  const id = Number(req.params.id);
  const folder = Number.isInteger(id) ? getFolder(id, userId) : undefined;

  if (!folder) {
    return res.status(404).json({ error: "folder not found" });
  }

  const { email } = req.body as { email?: unknown };
  if (!isNonEmptyString(email) || !isValidEmail(email.trim())) {
    return res.status(400).json({ error: "email must be valid" });
  }

  const sharedWithUser = getUserByEmail(email.trim().toLowerCase());
  if (!sharedWithUser) {
    return res.status(404).json({ error: "user not found" });
  }

  if (sharedWithUser.id === userId) {
    return res.status(400).json({ error: "cannot share a folder with its owner" });
  }

  const now = new Date().toISOString();
  db.prepare(
    `
      INSERT OR IGNORE INTO folder_shares (folder_id, owner_user_id, shared_with_user_id, created_at)
      VALUES (?, ?, ?, ?)
    `,
  ).run(folder.id, userId, sharedWithUser.id, now);

  const share = getFolderShare(folder.id, sharedWithUser.id);
  return res.status(201).json({
    ...share,
    folder,
    shared_with: toPublicUser(sharedWithUser),
  });
});

app.delete("/folders/:id/share/:userId", (req, res) => {
  const ownerId = requireUserId(req);
  const folderId = Number(req.params.id);
  const sharedWithUserId = Number(req.params.userId);
  const folder = Number.isInteger(folderId) ? getFolder(folderId, ownerId) : undefined;

  if (!folder || !Number.isInteger(sharedWithUserId)) {
    return res.status(404).json({ error: "share not found" });
  }

  const result = db
    .prepare("DELETE FROM folder_shares WHERE folder_id = ? AND owner_user_id = ? AND shared_with_user_id = ?")
    .run(folderId, ownerId, sharedWithUserId);

  if (result.changes === 0) {
    return res.status(404).json({ error: "share not found" });
  }

  return res.status(204).send();
});

app.get("/folders/:id", (req, res) => {
  const userId = requireUserId(req);
  const id = Number(req.params.id);
  const folder = Number.isInteger(id) ? getReadableFolder(id, userId) : undefined;

  if (!folder) {
    return res.status(404).json({ error: "folder not found" });
  }

  return res.status(200).json({ ...folder, bookmarks: getBookmarksForFolder(id, folder.user_id) });
});

app.put("/folders/:id", (req, res) => {
  const userId = requireUserId(req);
  const id = Number(req.params.id);
  const existing = Number.isInteger(id) ? getFolder(id, userId) : undefined;

  if (!existing) {
    if (Number.isInteger(id) && hasSharedFolderAccess(id, userId)) {
      return res.status(403).json({ error: "shared folders are read-only" });
    }

    return res.status(404).json({ error: "folder not found" });
  }

  const { name } = req.body as { name?: unknown };

  if (name !== undefined && !isNonEmptyString(name)) {
    return res.status(400).json({ error: "name must be a non-empty string" });
  }

  const updatedAt = new Date().toISOString();
  db.prepare("UPDATE folders SET name = ?, updated_at = ? WHERE id = ? AND user_id = ?").run(
    typeof name === "string" ? name.trim() : existing.name,
    updatedAt,
    id,
    userId,
  );

  return res.status(200).json(getFolder(id, userId));
});

app.delete("/folders/:id", (req, res) => {
  const userId = requireUserId(req);
  const id = Number(req.params.id);
  const existing = Number.isInteger(id) ? getFolder(id, userId) : undefined;

  if (!existing) {
    if (Number.isInteger(id) && hasSharedFolderAccess(id, userId)) {
      return res.status(403).json({ error: "shared folders are read-only" });
    }

    return res.status(404).json({ error: "folder not found" });
  }

  const transaction = db.transaction((folderId: number, ownerId: number) => {
    db.prepare(
      "UPDATE bookmarks SET folder_id = NULL, version = version + 1, updated_at = ? WHERE folder_id = ? AND user_id = ?",
    ).run(
      new Date().toISOString(),
      folderId,
      ownerId,
    );
    db.prepare("DELETE FROM folders WHERE id = ? AND user_id = ?").run(folderId, ownerId);
  });
  transaction(id, userId);

  return res.status(204).send();
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

export default app;
export { db };

