+  if (page === undefined || limit === undefined) {
+    return undefined;
+  }
+
+  return { page, limit };
+}
+
+function parseCursorQuery(value: Request["query"][string]): CursorPosition | null | undefined {
+  if (value === undefined || value === "") {
+    return null;
+  }
+
+  if (typeof value !== "string") {
+    return undefined;
+  }
+
+  const [encodedPayload, encodedSignature] = value.split(".");
+  if (!encodedPayload || !encodedSignature || value.split(".").length !== 2) {
+    return undefined;
+  }
+
+  const expectedSignature = signCursorPayload(encodedPayload);
+  const receivedSignature = Buffer.from(encodedSignature, "base64url");
+  if (
+    receivedSignature.length !== expectedSignature.length ||
+    !timingSafeEqual(receivedSignature, expectedSignature)
+  ) {
+    return undefined;
+  }
+
+  try {
+    const payload = JSON.parse(Buffer.from(encodedPayload, "base64url").toString("utf8")) as unknown;
+    if (!isCursorPayload(payload)) {
+      return undefined;
+    }
+
+    return {
+      created_at: payload.created_at,
+      id: payload.id,
+    };
+  } catch {
+    return undefined;
+  }
+}
+
+function encodeCursor(position: CursorPosition): string {
+  const payload: CursorPayload = {
+    v: 1,
+    created_at: position.created_at,
+    id: position.id,
+  };
+  const encodedPayload = Buffer.from(JSON.stringify(payload), "utf8").toString("base64url");
+  return `${encodedPayload}.${signCursorPayload(encodedPayload).toString("base64url")}`;
+}
+
+function signCursorPayload(encodedPayload: string): Buffer {
+  return createHmac("sha256", JWT_SECRET).update(encodedPayload).digest();
+}
+
+function isCursorPayload(value: unknown): value is CursorPayload {
+  return (
+    isPlainObject(value) &&
+    value.v === 1 &&
+    typeof value.created_at === "string" &&
+    value.created_at.length > 0 &&
+    typeof value.id === "number" &&
+    Number.isSafeInteger(value.id) &&
+    value.id > 0
+  );
+}
+
+function parseSearchQuery(query: Request["query"]): SearchQuery | null | undefined {
+  if (query.q === undefined) {
+    return null;
+  }
+
+  if (typeof query.q !== "string" || query.q.length > 200) {
+    return undefined;
+  }
+
+  const normalized = query.q.trim().toLowerCase();
+  if (normalized.length === 0) {
+    return null;
+  }
+
+  const escaped = escapeLikePattern(normalized);
+  return {
+    normalized,
+    prefixPattern: `${escaped}%`,
+    containsPattern: `%${escaped}%`,
+  };
+}
+
+function parsePaginationInteger(
+  value: Request["query"][string],
+  defaultValue: number,
+  min: number,
+  max: number,
+): number | undefined {
+  if (value === undefined) {
+    return defaultValue;
+  }
+
+  if (typeof value !== "string" || !/^\d+$/.test(value)) {
+    return undefined;
+  }
+
+  const parsed = Number(value);
+  if (!Number.isSafeInteger(parsed) || parsed < min || parsed > max) {
+    return undefined;
+  }
+
+  return parsed;
+}
+
+function escapeLikePattern(value: string): string {
+  return value.replace(/[\\%_]/g, (character) => `\\${character}`);
