+  if (search === undefined) {
+    return res.status(400).json({ error: "q must be a string no longer than 200 characters" });
+  }
+
+  const offset = (pagination.page - 1) * pagination.limit;
+  const tagFilter = buildTagFilterSql(tagNames);
+  const searchFilter = buildSearchSql(search);
+
+  if (cursorMode) {
+    const cursorClause = cursor ? "AND (created_at > ? OR (created_at = ? AND id > ?))" : "";
+    const cursorParams = cursor ? [cursor.created_at, cursor.created_at, cursor.id] : [];
+    const rows = db
+      .prepare(
+        `
+          SELECT id, user_id, url, title, description, folder_id, version, created_at, updated_at
+          FROM bookmarks
+          WHERE user_id = ?
+          ${tagFilter.clause}
+          ${searchFilter.clause}
+          ${cursorClause}
+          ORDER BY created_at ASC, id ASC
+          LIMIT ?
+        `,
+      )
+      .all(
+        userId,
+        ...tagFilter.params,
+        ...searchFilter.params,
+        ...cursorParams,
+        pagination.limit + 1,
+      ) as Bookmark[];
+    const hasMore = rows.length > pagination.limit;
+    const bookmarks = hasMore ? rows.slice(0, pagination.limit) : rows;
+    const lastBookmark = bookmarks[bookmarks.length - 1];
+
+    return res.status(200).json({
+      data: attachBookmarkData(bookmarks, userId),
+      limit: pagination.limit,
+      nextCursor: hasMore && lastBookmark ? encodeCursor(lastBookmark) : null,
+      hasMore,
+    });
+  }
+
+  const countParams = [userId, ...tagFilter.params, ...searchFilter.params];
+  const { total } = db
+    .prepare(
+      `
+        SELECT COUNT(*) AS total
+        FROM bookmarks
+        WHERE user_id = ?
+        ${tagFilter.clause}
+        ${searchFilter.clause}
+      `,
+    )
+    .get(...countParams) as { total: number };
+  const bookmarks = db
+    .prepare(
+      `
+        SELECT id, user_id, url, title, description, folder_id, version, created_at, updated_at
+        FROM bookmarks
+        WHERE user_id = ?
+        ${tagFilter.clause}
+        ${searchFilter.clause}
+        ORDER BY ${searchFilter.orderBy}
+        LIMIT ? OFFSET ?
+      `,
+    )
+    .all(userId, ...tagFilter.params, ...searchFilter.params, ...searchFilter.orderParams, pagination.limit, offset) as Bookmark[];
+
+  return res.status(200).json({
+    data: attachBookmarkData(bookmarks, userId),
+    page: pagination.page,
+    limit: pagination.limit,
+    total,
+  });
+});
